+const reloadStatusFilename = "reload-status.json"
+
+// reloadStatusTracker keeps the last transactional reload result and its
+// corresponding known-good configuration. Status persistence is deliberately
+// best-effort: a filesystem error must never interfere with startup or reloads.
+type reloadStatusTracker struct {
+	mu        sync.RWMutex
+	path      string
+	logger    *slog.Logger
+	status    api_v1.ReloadStatus
+	knownGood *config.Config
+}
+
+func newReloadStatusTracker(storagePath string, logger *slog.Logger) *reloadStatusTracker {
+	t := &reloadStatusTracker{
+		path:   filepath.Join(storagePath, reloadStatusFilename),
+		logger: logger,
+		status: emptyReloadStatus(),
+	}
+
+	b, err := os.ReadFile(t.path)
+	if err != nil {
+		return t
+	}
+	var status api_v1.ReloadStatus
+	if err := json.Unmarshal(b, &status); err != nil {
+		logger.Warn("Ignoring invalid persisted reload status", "file", t.path, "err", err)
+		return t
+	}
+	status = normalizeReloadStatus(status)
+	t.status = status
+	return t
+}
+
+func emptyReloadStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{
+		ErrorCategory:     "none",
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]int64{},
+	}
+}
+
+func normalizeReloadStatus(status api_v1.ReloadStatus) api_v1.ReloadStatus {
+	if status.ErrorCategory == "" {
+		status.ErrorCategory = "none"
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]int64{}
+	}
+	return status
+}
+
+func (t *reloadStatusTracker) Status() api_v1.ReloadStatus {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	status := t.status
+	status.AppliedReloaders = append([]string(nil), status.AppliedReloaders...)
+	status.ReloaderTimingsMS = make(map[string]int64, len(status.ReloaderTimingsMS))
+	for name, duration := range status.ReloaderTimingsMS {
+		status.ReloaderTimingsMS[name] = duration
+	}
+	return status
+}
+
+func (t *reloadStatusTracker) SetKnownGood(conf *config.Config) {
+	t.mu.Lock()
+	defer t.mu.Unlock()
+	t.knownGood = conf
+}
+
+func (t *reloadStatusTracker) KnownGood() *config.Config {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	return t.knownGood
+}
+
+func (t *reloadStatusTracker) Record(status api_v1.ReloadStatus) {
+	status = normalizeReloadStatus(status)
+	t.mu.Lock()
+	t.status = status
+	b, err := json.Marshal(status)
+	if err == nil {
+		tmp, createErr := os.CreateTemp(filepath.Dir(t.path), ".reload-status-*")
+		if createErr == nil {
+			_, writeErr := tmp.Write(b)
+			closeErr := tmp.Close()
+			if writeErr == nil && closeErr == nil {
+				err = os.Rename(tmp.Name(), t.path)
+			} else if writeErr != nil {
+				err = writeErr
+			} else {
+				err = closeErr
+			}
+			if err != nil {
+				_ = os.Remove(tmp.Name())
+			}
+		} else {
+			err = createErr
+		}
+	}
+	t.mu.Unlock()
+	if err != nil {
+		t.logger.Warn("Failed to persist reload status", "file", t.path, "err", err)
+	}
+}
