+func reloadConfigTransactionally(conf *config.Config, filename string, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, transactional *reloadStatusTracker, recordOutcome bool, rls ...reloader) error {
+	status := api_v1.ReloadStatus{
+		LastReloadID:       time.Now().UTC().Format(time.RFC3339),
+		ErrorCategory:      "none",
+		AppliedReloaders:   []string{},
+		ReloaderTimingsMS:  map[string]int64{},
+	}
+
+	for i, rl := range rls {
+		start := time.Now()
+		err := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = time.Since(start).Milliseconds()
+		if err == nil {
+			status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+			continue
+		}
+
+		status.LastReloadSuccessful = false
+		status.ErrorCategory = "apply_error"
+		status.ErrorMessage = err.Error()
+		status.FailedReloader = rl.name
+		logger.Error("Failed to apply configuration", "reloader", rl.name, "err", err)
+
+		if i > 0 {
+			status.RollbackAttempted = true
+			knownGood := transactional.KnownGood()
+			status.RollbackSuccessful = knownGood != nil
+			if knownGood != nil {
+				for _, applied := range rls[:i] {
+					if rollbackErr := applied.reloader(knownGood); rollbackErr != nil {
+						status.RollbackSuccessful = false
+						status.ErrorCategory = "rollback_error"
+						status.ErrorMessage = fmt.Sprintf("failed to roll back reloader %q: %v", applied.name, rollbackErr)
+						logger.Error("Failed to roll back configuration", "reloader", applied.name, "err", rollbackErr)
+						break
+					}
+				}
+			}
+		}
+		if recordOutcome {
+			transactional.Record(status)
+		}
+		return fmt.Errorf("failed to apply configuration with reloader %q (--config.file=%q): %w", rl.name, filename, err)
+	}
+
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	transactional.SetKnownGood(conf)
+	if recordOutcome {
+		status.LastReloadSuccessful = true
+		transactional.Record(status)
+	}
+	return nil
+}
